import logging
import math
import time
from enum import Enum, unique

import numpy as np
from geosat.cloud import pyvoxels, PointCloud


def softmax(x, theta=1.0, axis=None):
    # make X at least 2d
    y = np.atleast_2d(x)

    # find axis
    if axis is None:
        axis = next(j[0] for j in enumerate(y.shape) if j[1] > 1)

    # multiply y against the theta parameter,
    y = y * float(theta)

    # subtract the max for numerical stability
    y = y - np.expand_dims(np.max(y, axis=axis), axis)

    # exponentiate y
    y = np.exp(y)

    # take the sum along the specified axis
    ax_sum = np.expand_dims(np.sum(y, axis=axis), axis)

    # finally: divide elementwise
    p = y / ax_sum

    # flatten if X was 1D
    if len(x.shape) == 1:
        p = p.flatten()

    return p


# Workaround to use cvoxel with arbitrary list of points
def to_pointcloud(coords):
    return PointCloud(coords)


# Computes relative indices of rectangular neighborhood
def rectangular_neighborhood(window):
    half_w = math.floor(window[0] / 2)
    half_l = math.floor(window[1] / 2)
    half_h = math.floor(window[2] / 2)

    x = np.arange(window[0]) - half_w
    y = np.arange(window[1]) - half_l
    z = np.arange(window[2]) - half_h

    xx, yy, zz = np.meshgrid(x, y, z)

    return np.vstack([xx.flatten(), yy.flatten(), zz.flatten()]).astype(np.int_).T


@unique
class DataLoaderFlag(Enum):
    TRAINING = 1
    VALIDATION = 2
    TEST = 3


class LazLoader:
    def __init__(self, laz, settings):
        # Storing settings
        self.settings = settings

        logging.debug("Preparing point cloud")

        # Voxelizing
        self._voxelize(laz)

        logging.debug(" - Preparation is done.")

        # Batch generation variables
        self._perm_idx = []
        self._batch_idx = []
        self._cur_idx = 0
        self._batch_voxels_idx = []
        self._batch_voxels_coords = []

    def _voxelize(self, laz):
        logging.debug(" - Voxelizing point cloud ...")
        t = time.time()
        self.laz = laz
        self.voxels = pyvoxels.voxelize_cloud(self.laz, self.settings.data.voxel_size)
        self.voxels_map = list(self.voxels.keys())
        self.voxels_map_inv = {v: i for i, v in enumerate(self.voxels_map)}
        self.voxels_coords = np.array(self.voxels_map) * self.settings.data.voxel_size
        self.voxels_labels = np.zeros(len(self.voxels_coords), dtype="u1")
        logging.debug(
            " - {} voxels found ({:0.2f}s)".format(
                len(self.voxels_coords), time.time() - t
            )
        )

        logging.debug(" - Creating volumes ...")
        pc = to_pointcloud(self.voxels_coords)
        self.volumes = pyvoxels.voxelize_cloud(pc, self.settings.data.volume_size)
        self.volumes_map = list(self.volumes.keys())
        logging.debug(
            " - {} volumes found ({:0.2f}s)".format(len(self.volumes), time.time() - t)
        )

    def _shuffle_voxel_idx(self):
        num_volumes = len(self.volumes)
        if num_volumes % self.settings.network.batch_size == 0:
            self._perm_idx = np.arange(num_volumes)
        else:  # Ensure that last index is repeated for last batch that will be processed
            self._perm_idx = np.hstack(
                [
                    np.arange(num_volumes),
                    np.full(
                        self.settings.network.batch_size
                        - (num_volumes % self.settings.network.batch_size),
                        num_volumes - 1,
                    ),
                ]
            )
        self._cur_idx = 0

    def get_iterations_number(self):
        return math.ceil(len(self.volumes) / self.settings.network.batch_size)

    def read_batch(self):
        batch_size = self.settings.network.batch_size
        voxel_size = self.settings.data.voxel_size
        volume_size = self.settings.data.volume_size
        volume_window = np.array(self.settings.data.volume_window)

        # If next batch goes across generated list, regenerate it
        if self._cur_idx + batch_size > len(self._perm_idx):
            self._shuffle_voxel_idx()

        # Extract voxel idx for the current batch
        self._batch_idx = self._perm_idx[self._cur_idx : self._cur_idx + batch_size]
        self._cur_idx += batch_size

        # Compute dimensions
        volume_side = round(volume_size / voxel_size)
        volume_output_dim = np.round(volume_window * volume_size / voxel_size).astype(
            np.int_
        )
        volume_center_start = np.round(
            (volume_output_dim / 2 - volume_side / 2)
        ).astype(np.int_)

        # If window is even, extend it by 1 to have symmetric neighborhood around center volume
        if np.sum(volume_window % 2) == 0:
            volume_window = volume_window + 1
            volume_final_offset = int(volume_side / 2)
            volume_dim = np.round(volume_window * volume_side).astype(np.int_)
        else:
            volume_final_offset = 0
            volume_dim = volume_output_dim

        # For augmentation, batch should be extended in each direction
        neighborhood = rectangular_neighborhood(volume_window)
        neighborhood_min = np.min(neighborhood, axis=0)

        # Keep track of processed data
        self._batch_voxels_idx = []
        self._batch_voxels_coords = []

        # Create output
        occupancy_grid = np.full(
            (
                batch_size,
                volume_output_dim[0],
                volume_output_dim[1],
                volume_output_dim[2],
            ),
            -1,
        )

        # If training, labels should also be computed
        output_mask = np.zeros((batch_size, volume_side, volume_side, volume_side))

        # Iterates through batch indices
        for b_i, idx in enumerate(self._batch_idx):
            v = self.volumes_map[idx]

            # Compute neighboring volumes
            nvs = pyvoxels.find_neighbours(v, self.volumes, neighborhood)

            # Retrieve point indices in the volume
            voxels_idx = np.array([index for nv in nvs for index in self.volumes[nv]])
            voxels_local_coords = np.floor(
                (
                    self.voxels_coords[voxels_idx, :]
                    - (np.array(v) + neighborhood_min) * volume_size
                )
                / voxel_size
            ).astype(np.int_)

            # Compute voxel coordinates of points
            occ = np.full(volume_dim, -1)
            occ[tuple(voxels_local_coords.T)] = voxels_idx

            occ = occ[
                volume_final_offset : occ.shape[0] - volume_final_offset,
                volume_final_offset : occ.shape[1] - volume_final_offset,
                volume_final_offset : occ.shape[2] - volume_final_offset,
            ]

            occupancy_grid[b_i, ...] = occ > -1

            occ_center = occ[
                volume_center_start[0] : volume_center_start[0] + volume_side,
                volume_center_start[1] : volume_center_start[1] + volume_side,
                volume_center_start[2] : volume_center_start[2] + volume_side,
            ]
            voxels_idx = occ_center[occ_center > -1]
            occ_center[occ_center > -1] = self.voxels_labels[voxels_idx]
            self._batch_voxels_idx.append(voxels_idx)

            output_mask[b_i, ...] = occ_center > -1

        # Find most represented label in each voxel
        return occupancy_grid, output_mask

    def reset_outputs(self):
        # Batch generation variables
        self._perm_idx = []
        self._batch_idx = []
        self._cur_idx = 0
        self._batch_voxels_idx = []
        self._batch_voxels_coords = []

    def project_batch(self, predictions, mask):
        if predictions.ndim > 4:
            softmax_predictions = softmax(predictions, axis=-1)
            labels = np.argmax(softmax_predictions, axis=-1)
        else:
            labels = predictions

        # Iterate through each voxel of the batch
        for i in range(len(self._batch_idx)):
            idx = self._batch_voxels_idx[i]
            label_block = np.squeeze(labels[i, ...])
            label = label_block[mask[i, ...] == 1]

            self.voxels_labels[idx] = label

    def map_voxels_labels_to_pointcloud(self):
        for vi, points in enumerate(self.voxels.values()):
            self.laz.classification[points] = self.voxels_labels[vi]

    # Refine labels close to ground by fitting a plane on surrounding/ground-only voxels points
    def refine_ground(
        self, ground_class=1.0, plane_dist_tolerance=0.05, neighborhood_window=(5, 5, 1)
    ):
        # Get above voxel
        def v_above(voxel):
            return voxel[0], voxel[1], voxel[2] + 1

        # Compute plane equation coefficient from PCA
        def plane_coeff_from_pca(data):
            mean_point = np.mean(data, axis=0)
            data_adjust = data - mean_point
            matrix = np.cov(data_adjust.T)

            eigenvalues, eigenvectors = np.linalg.eig(matrix)

            sort = eigenvalues.argsort()[::-1]
            eigenvectors = eigenvectors[:, sort]

            # Compute plane coeff
            normal = eigenvectors[:, 2]
            _a, _b, _c = normal
            _d = -np.dot(normal, mean_point)
            return _a, _b, _c, _d

        # Compute mask of points that are close enough to plane
        def plane_inliers(_points, _a, _b, _c, _d, dist_tolerance=0.05):
            _d = np.abs(
                _a * _points[:, 0] + _b * _points[:, 1] + _c * _points[:, 2] + _d
            ) / np.sqrt(_a**2 + _b**2 + _c**2)

            return _d < dist_tolerance

        neighborhood = rectangular_neighborhood(neighborhood_window)
        for v_i, (v, points) in enumerate(self.voxels.items()):
            if (
                self.voxels_labels[v_i] == ground_class
                and v_above(v) in self.voxels
                and self.voxels_labels[self.voxels_map_inv[v_above(v)]] != ground_class
            ):
                nvs = pyvoxels.find_neighbours(v, self.voxels, neighborhood)

                # Retrieve points of neighboring voxels that have no "above" voxels
                ground_points = [
                    p
                    for nv in nvs
                    if self.voxels_labels[self.voxels_map_inv[nv]] == ground_class
                    and not v_above(nv) in self.voxels
                    for p in self.voxels[nv]
                ]

                # At least 3 points are required to compute PCA
                if len(ground_points) < 3:
                    continue

                # Compute inliers towards plane
                a, b, c, d = plane_coeff_from_pca(self.laz.coords[ground_points, :])
                inliers_mask = plane_inliers(
                    self.laz.coords[points, :],
                    a,
                    b,
                    c,
                    d,
                    dist_tolerance=plane_dist_tolerance,
                )

                if np.sum(~inliers_mask) > 0:
                    self.laz.classification[np.array(points)[~inliers_mask]] = (
                        self.voxels_labels[self.voxels_map_inv[v_above(v)]]
                    )
